'use client';

import React, { useState, useRef, useEffect } from 'react';
import Image from 'next/image';
import {
  Send,
  Sparkles,
  Plus,
  Calendar,
  Tag,
  CheckCircle2,
  ArrowRight,
  Pencil,
  Check,
  X
} from 'lucide-react';
import { AppLayout } from '@/src/components/layout/AppLayout';
import { Card, CardHeader, CardContent } from '@/src/components/ui/Card';
import { Button } from '@/src/components/ui/Button';
import { Modal } from '@/src/components/ui/Modal';
import { cn } from '@/src/lib/utils';

interface Message {
  id: string;
  role: 'assistant' | 'user';
  content: string;
  type?: 'text' | 'promo-card';
  data?: { title: string; price: string; originalPrice: string; emoji: string; slots: number };
}

const INITIAL_MESSAGES: Message[] = [
  {
    id: '1',
    role: 'assistant',
    content: "Hi! I'm your AI Growth Assistant. I can help you create high-converting promotions for your restaurant. What would you like to promote today?",
    type: 'text'
  }
];

const inputCls = "w-full bg-g-faint border border-border-light rounded-xl px-4 py-2.5 text-sm outline-none focus:border-g-dark focus:ring-2 focus:ring-g-pale transition-all";
const labelCls = "block text-xs font-bold text-text-dark mb-1.5";

export default function Promotions() {
  const [messages, setMessages] = useState<Message[]>(INITIAL_MESSAGES);
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  // Launch promo modal state
  const [launchModal, setLaunchModal] = useState<Message['data'] | null>(null);
  const [launched, setLaunched] = useState(false);

  // Edit draft modal state
  const [editModal, setEditModal] = useState<Message['data'] | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editPrice, setEditPrice] = useState('');
  const [editSaved, setEditSaved] = useState(false);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = (overrideInput?: string) => {
    const text = (overrideInput ?? input).trim();
    if (!text) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: text };
    setMessages(prev => [...prev, userMsg]);
    setInput('');

    setTimeout(() => {
      const aiMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: "That sounds like a great idea! Based on your sales data, a 'Burger Bundle' would perform exceptionally well on Tuesdays. Here's a draft promotion I've created for you:",
        type: 'promo-card',
        data: { title: 'Burger Bundle!', price: '£12.99', originalPrice: '£16.99', emoji: '🍔', slots: 7 }
      };
      setMessages(prev => [...prev, aiMsg]);
    }, 1000);
  };

  const openEdit = (data: Message['data']) => {
    setEditTitle(data?.title ?? '');
    setEditPrice(data?.price ?? '');
    setEditSaved(false);
    setEditModal(data ?? null);
  };

  return (
    <AppLayout
      title="Promotions"
      subtitle="Create and manage AI-powered promotions to drive more orders."
    >
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Chat Interface */}
        <Card className="lg:col-span-2 flex flex-col min-h-[500px] lg:h-[calc(100vh-12rem)]">
          <CardHeader className="flex flex-row items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl overflow-hidden shrink-0">
                <Image src="/images/robot-thinking.jpeg" alt="AI Assistant" width={40} height={40} className="w-full h-full object-cover" />
              </div>
              <div>
                <h3 className="text-sm font-bold text-text-dark">AI Growth Assistant</h3>
                <p className="text-[10px] text-g-dark font-bold flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-g-dark animate-pulse" /> Online
                </p>
              </div>
            </div>
            <Button
              variant="outline"
              size="sm"
              onClick={() => setMessages(INITIAL_MESSAGES)}
            >
              Reset Chat
            </Button>
          </CardHeader>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 bg-g-faint/30">
            {messages.map((m) => (
              <div key={m.id} className={cn("flex gap-4", m.role === 'user' ? "flex-row-reverse" : "")}>
                <div className={cn(
                  "w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold shrink-0 overflow-hidden",
                  m.role === 'assistant' ? "" : "bg-gray-200 text-gray-600"
                )}>
                  {m.role === 'assistant'
                    ? <Image src="/images/robot-happy.jpeg" alt="AI" width={32} height={32} className="w-full h-full object-cover" />
                    : 'U'
                  }
                </div>
                <div className={cn("max-w-[80%] space-y-4", m.role === 'user' ? "text-right" : "")}>
                  <div className={cn(
                    "p-4 rounded-2xl text-sm shadow-sm",
                    m.role === 'assistant' ? "bg-white text-text-dark border border-border-light" : "bg-g-dark text-white"
                  )}>
                    {m.content}
                  </div>

                  {m.type === 'promo-card' && m.data && (
                    <div className="bg-white p-5 rounded-2xl border border-border-light shadow-md max-w-sm ml-0 mr-auto space-y-4">
                      <div className="flex gap-4">
                        <div className="w-20 h-20 bg-g-pale rounded-xl flex items-center justify-center text-3xl shrink-0">
                          {m.data.emoji}
                        </div>
                        <div className="flex-1 min-w-0">
                          <h4 className="text-base font-bold text-text-dark">{m.data.title}</h4>
                          <div className="flex items-center gap-2 mt-1">
                            <span className="text-lg font-bold text-g-dark">{m.data.price}</span>
                            <span className="text-xs text-text-muted line-through">{m.data.originalPrice}</span>
                          </div>
                          <p className="text-[10px] text-text-muted mt-1">Only {m.data.slots} slots left today.</p>
                        </div>
                      </div>
                      <div className="flex gap-2">
                        <Button className="flex-1 py-2 text-xs" onClick={() => { setLaunched(false); setLaunchModal(m.data ?? null); }}>
                          Launch Now
                        </Button>
                        <Button variant="outline" className="flex-1 py-2 text-xs gap-1" onClick={() => openEdit(m.data)}>
                          <Pencil className="w-3 h-3" /> Edit Draft
                        </Button>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>

          <div className="p-4 border-t border-border-light bg-white">
            <div className="flex gap-2 bg-g-faint p-2 rounded-xl border border-border-light">
              <input
                type="text"
                placeholder="Ask me to create a promo for slow Tuesdays…"
                className="flex-1 bg-transparent border-none outline-none text-sm px-2"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              />
              <button
                onClick={() => handleSend()}
                className="bg-g-dark text-white p-2 rounded-lg hover:bg-g-mid transition-all"
              >
                <Send className="w-4 h-4" />
              </button>
            </div>
            <div className="flex gap-2 mt-3 overflow-x-auto pb-1 no-scrollbar">
              {['Suggest A Promo', 'Current offers', 'Get More Customers', 'Create a Post'].map(a => (
                <button
                  key={a}
                  onClick={() => handleSend(a)}
                  className="px-3 py-1.5 bg-white border border-border-light rounded-full text-[10px] font-bold text-text-mid hover:bg-g-pale hover:text-g-dark transition-all whitespace-nowrap"
                >
                  + {a}
                </button>
              ))}
            </div>
          </div>
        </Card>

        {/* Sidebar Info */}
        <div className="space-y-6">
          <Card className="p-6 bg-gradient-to-br from-g-dark to-g-mid text-white border-none">
            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
              <Sparkles className="w-5 h-5" /> AI Tips
            </h3>
            <div className="space-y-4">
              {[
                { icon: Calendar, text: "Tuesdays are your slowest days. Launch a 'Mid-week Treat' promo." },
                { icon: Tag, text: "Your 'Burger Bundle' has a 45% conversion rate. Promote it more!" },
                { icon: CheckCircle2, text: "Adding a 'Limited Time' tag increases clicks by 22%." }
              ].map((tip, i) => (
                <div key={i} className="flex gap-3 bg-white/10 p-4 rounded-xl backdrop-blur-sm">
                  <tip.icon className="w-5 h-5 shrink-0" />
                  <p className="text-xs leading-relaxed">{tip.text}</p>
                </div>
              ))}
            </div>
          </Card>

          <Card className="p-6">
            <h3 className="text-sm font-bold text-text-dark mb-4">Active Promotions</h3>
            <div className="space-y-4">
              {[
                { name: 'Lunch Special', status: 'Active', orders: 24 },
                { name: 'Weekend Feast', status: 'Paused', orders: 12 },
              ].map((p, i) => (
                <div key={i} className="flex items-center justify-between p-3 bg-g-faint rounded-xl border border-border-light">
                  <div>
                    <p className="text-sm font-bold text-text-dark">{p.name}</p>
                    <p className="text-[10px] text-text-muted">{p.orders} orders generated</p>
                  </div>
                  <span className={cn(
                    "px-2 py-0.5 rounded-full text-[10px] font-bold",
                    p.status === 'Active' ? "bg-g-pale text-g-dark" : "bg-gray-100 text-gray-500"
                  )}>{p.status}</span>
                </div>
              ))}
            </div>
            <Button variant="outline" className="w-full mt-6 text-xs" onClick={() => window.location.href = '/campaigns'}>
              View All Campaigns <ArrowRight className="w-3 h-3 ml-2" />
            </Button>
          </Card>
        </div>
      </div>

      {/* Launch Now Modal */}
      <Modal
        open={!!launchModal}
        onClose={() => setLaunchModal(null)}
        title="Launch Promotion"
        size="sm"
      >
        {launched ? (
          <div className="flex flex-col items-center gap-4 py-2 text-center">
            <div className="w-14 h-14 bg-g-pale rounded-full flex items-center justify-center">
              <Check className="w-7 h-7 text-g-dark" />
            </div>
            <div>
              <p className="font-bold text-text-dark">Promotion Launched!</p>
              <p className="text-xs text-text-muted mt-1">
                <strong>"{launchModal?.title}"</strong> is now live on all connected platforms.
              </p>
            </div>
            <Button className="w-full" onClick={() => setLaunchModal(null)}>Done</Button>
          </div>
        ) : (
          <div className="space-y-4">
            {launchModal && (
              <div className="flex items-center gap-4 p-3 bg-g-faint rounded-xl border border-border-light">
                <span className="text-3xl">{launchModal.emoji}</span>
                <div>
                  <p className="text-sm font-bold text-text-dark">{launchModal.title}</p>
                  <p className="text-xs text-text-muted">
                    <span className="font-bold text-g-dark">{launchModal.price}</span>
                    <span className="line-through ml-2">{launchModal.originalPrice}</span>
                  </p>
                </div>
              </div>
            )}
            <div className="p-3 bg-g-faint rounded-xl border border-border-light space-y-1">
              <p className="text-[10px] font-bold text-text-muted uppercase tracking-widest">Will go live on</p>
              <div className="flex gap-2 flex-wrap mt-1">
                {['Uber Eats', 'Deliveroo', 'Just Eat'].map(p => (
                  <span key={p} className="text-[10px] font-bold bg-white border border-border-light px-2 py-1 rounded-lg text-text-mid">{p}</span>
                ))}
              </div>
            </div>
            <div className="flex gap-2">
              <Button variant="outline" className="flex-1" onClick={() => setLaunchModal(null)}>Cancel</Button>
              <Button className="flex-1" onClick={() => setLaunched(true)}>Confirm Launch</Button>
            </div>
          </div>
        )}
      </Modal>

      {/* Edit Draft Modal */}
      <Modal
        open={!!editModal}
        onClose={() => setEditModal(null)}
        title={<span className="flex items-center gap-2"><Pencil className="w-4 h-4 text-g-dark" /> Edit Draft</span>}
        size="sm"
      >
        {editSaved ? (
          <div className="flex flex-col items-center gap-4 py-2 text-center">
            <div className="w-14 h-14 bg-g-pale rounded-full flex items-center justify-center">
              <Check className="w-7 h-7 text-g-dark" />
            </div>
            <div>
              <p className="font-bold text-text-dark">Draft Saved!</p>
              <p className="text-xs text-text-muted mt-1">Your promo draft has been updated.</p>
            </div>
            <Button className="w-full" onClick={() => setEditModal(null)}>Done</Button>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="space-y-3">
              <label className="block">
                <span className={labelCls}>Promo Title</span>
                <input type="text" value={editTitle} onChange={e => setEditTitle(e.target.value)} className={inputCls} />
              </label>
              <label className="block">
                <span className={labelCls}>Promo Price</span>
                <input type="text" value={editPrice} onChange={e => setEditPrice(e.target.value)} className={inputCls} />
              </label>
            </div>
            <div className="flex gap-2">
              <Button variant="outline" className="flex-1" onClick={() => setEditModal(null)}>
                <X className="w-4 h-4" /> Cancel
              </Button>
              <Button className="flex-1 gap-1" onClick={() => setEditSaved(true)}>
                <Check className="w-4 h-4" /> Save Draft
              </Button>
            </div>
          </div>
        )}
      </Modal>
    </AppLayout>
  );
}
